const D = 8200;
const WALL_T = 250;
const INT_T = 120;
const GLASS_T = 80;
const SHELL_T = 550;
const LOGGIA_Y = 1100;
const CUT_X0 = 5400;
const CUT_X1 = UPPER_W;
const CUT_Y0 = 3300;
const CUT_Y1 = 6500;
const EAVE_L = 2500;
const EAVE_R = 2350;
const RIDGE_OFF = 450;
const SLOPE_DEG = 23;
const RIDGE_X = UPPER_W / 2 + RIDGE_OFF;
const RIDGE_H_ABS =
  F2F + EAVE_L + Math.round(RIDGE_X * Math.tan((SLOPE_DEG * Math.PI) / 180));

function pt(xMm, yMm) {
  return { xMm, yMm };
}

function rect(x0, y0, x1, y1) {
  return [pt(x0, y0), pt(x1, y0), pt(x1, y1), pt(x0, y1)];
}

function areaM2(x0, y0, x1, y1) {
  return Number((((x1 - x0) * (y1 - y0)) / 1_000_000).toFixed(2));
}

function wallTypeFor(materialKey, thicknessMm) {
  if (materialKey === 'glass_clear') return 'hf-wt-glass';
  if (materialKey === 'cladding_warm_wood') return 'hf-wt-cladding';
  if (thicknessMm <= 140) return 'hf-wt-internal';
  return 'hf-wt-white-render';
}

function wall(id, name, levelId, x0, y0, x1, y1, heightMm, materialKey = null, thicknessMm = WALL_T) {
  return {
    type: 'createWall',
    id,
    name,
    levelId,
    start: pt(x0, y0),
    end: pt(x1, y1),
    thicknessMm,
    heightMm,
    wallTypeId: wallTypeFor(materialKey, thicknessMm),
    materialKey,
    isCurtainWall: materialKey === 'glass_clear',
  };
}

function mass(id, name, levelId, x0, y0, x1, y1, heightMm, materialKey) {
  return {
    type: 'createMass',
    id,
    name,
    levelId,
    footprintMm: rect(x0, y0, x1, y1),
    heightMm,
    materialKey,
  };
}

function profileRect(widthMm, depthMm) {
  const w = widthMm / 2;
  const d = depthMm / 2;
  return [
    { uMm: -w, vMm: -d },
    { uMm: w, vMm: -d },
    { uMm: w, vMm: d },
    { uMm: -w, vMm: d },
  ];
}

function sweep(id, name, pathMm, materialKey, widthMm = 45, depthMm = 45) {
  return {
    type: 'createSweep',
    id,
    name,
    levelId: 'hf-lvl-ground',
    pathMm,
    profileMm: profileRect(widthMm, depthMm),
    profilePlane: 'work_plane',
    materialKey,
  };
}

function verticalBatten(id, name, xMm, yMm, z0Mm, z1Mm, materialKey = 'aluminium_dark_grey') {
  return sweep(
    id,
    name,
    [
      { xMm, yMm, zMm: z0Mm },
      { xMm, yMm, zMm: z1Mm },
    ],
    materialKey,
    18,
    24,
  );
}

function room(id, name, levelId, x0, y0, x1, y1, programmeCode, functionLabel, finishSet) {
  return {
    type: 'createRoomOutline',
    id,
    name,
    levelId,
    outlineMm: rect(x0, y0, x1, y1),
    programmeCode,
    functionLabel,
    finishSet,
    targetAreaM2: areaM2(x0, y0, x1, y1),
  };
}

function asset(id, name, category, width, height, tags = []) {
  return {
    type: 'IndexAsset',
    id,
    name,
    category,
    tags: [...tags, 'seed'],
    thumbnailWidthMm: width,
    thumbnailHeightMm: height,
  };
}

function place(id, assetId, name, levelId, xMm, yMm, rotationDeg = 0) {
  return {
    type: 'PlaceAsset',
    id,
    assetId,
    name,
    levelId,
    positionMm: pt(xMm, yMm),
    rotationDeg,
  };
}

const claddingBattens = [
  ...Array.from({ length: 17 }, (_, i) =>
    verticalBatten(`hf-sw-gf-front-batten-${i + 1}`, `GF front vertical cladding batten ${i + 1}`, 1450 + i * 310, -22, 120, 2920),
  ),
  ...Array.from({ length: 15 }, (_, i) =>
    verticalBatten(`hf-sw-gf-east-batten-${i + 1}`, `GF east vertical cladding batten ${i + 1}`, GF_X1 + 22, 350 + i * 500, 120, 2920),
  ),
