    ([snapshot, pvId]) => {
      type StoreShape = {
        getState: () => {
          elementsById: Record<string, { kind?: string }>;
          hydrateFromSnapshot: (s: typeof snapshot) => void;
          activatePlanView: (id: string) => void;
          setViewerMode: (mode: string) => void;
        };
      };
      const win = window as unknown as { __bimStore?: StoreShape };
      if (!win.__bimStore) throw new Error('window.__bimStore not exposed');
      const st = win.__bimStore.getState();
      st.hydrateFromSnapshot(snapshot);
      st.activatePlanView(pvId as string);
      st.setViewerMode('plan_canvas');
      const next = win.__bimStore.getState();
      return {
        total: Object.keys(next.elementsById).length,
        walls: Object.values(next.elementsById).filter((e) => e.kind === 'wall').length,
        rooms: Object.values(next.elementsById).filter((e) => e.kind === 'room').length,
