import fs from 'node:fs';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

import { expect, test, type Page } from '@playwright/test';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const FIXTURE_PATH = path.join(__dirname, '__fixtures__', 'seed-target-house-snapshot.json');

async function boot(page: Page) {
  await page.addInitScript(() => {
    localStorage.setItem('bim.welcome.dismissed', '1');
    localStorage.setItem('bim.onboarding-completed', 'true');
    localStorage.setItem('bim.workspaceLayout', 'split_plan_3d');
  });
  await page.route('**/api/bootstrap', async (route) =>
    route.fulfill({ status: 200, contentType: 'application/json', body: '{"projects":[]}' }),
  );
  await page.route('**/api/models/*/comments**', async (route) =>
    route.fulfill({ status: 200, body: '{}' }),
  );
  await page.route('**/api/models/*/activity**', async (route) =>
    route.fulfill({ status: 200, body: '{"events":[]}' }),
  );
  await page.route('**/api/building-presets**', async (route) =>
    route.fulfill({ status: 200, contentType: 'application/json', body: '{"presets":{"residential":{}}}' }),
  );
  await page.goto('/');
  await page.waitForSelector('[data-testid="app-shell"]', { timeout: 30_000 });
}

async function capture(page: Page, planViewId: string, outPath: string) {
  const snap = JSON.parse(fs.readFileSync(FIXTURE_PATH, 'utf8'));
  await page.evaluate(
    ([snapshot, pvId]) => {
      type StoreShape = {
        getState: () => {
          hydrateFromSnapshot: (s: typeof snapshot) => void;
          activatePlanView: (id: string) => void;
          setViewerMode: (mode: string) => void;
        };
      };
      const st = (window as unknown as { __bimStore?: StoreShape }).__bimStore?.getState();
      if (!st) throw new Error('window.__bimStore not exposed');
      st.hydrateFromSnapshot(snapshot);
      st.activatePlanView(pvId as string);
      st.setViewerMode('plan_canvas');
    },
    [snap, planViewId] as const,
  );
  const canvas = page.locator('[data-testid="plan-canvas"]');
  await expect(canvas).toBeVisible({ timeout: 30_000 });
  const box = await canvas.boundingBox();
  if (!box) throw new Error('missing plan canvas bbox');
  await page.mouse.move(box.x + box.width / 2, box.y + box.height / 2);
  await page.waitForTimeout(500);
  for (let i = 0; i < 8; i += 1) {
    await page.mouse.wheel(0, -850);
    await page.waitForTimeout(80);
  }
  await page.waitForTimeout(800);
  await canvas.screenshot({ path: outPath });
}

test('capture seedhouse plan diagnostics', async ({ page }) => {
  await boot(page);
  await capture(page, 'hf-pv-ground', '../../nightshift/seedhouse-rebuild-2026-05-10-ground-plan-diagnostic.png');
  await capture(page, 'hf-pv-upper', '../../nightshift/seedhouse-rebuild-2026-05-10-upper-plan-diagnostic.png');
});

